            'b640390c8aae2617b88a22e343de605d2e7e0b9c 1 1 60\nauthor Hina Tanaka\nauthor-mail <hina.tanaka@example.com>\nauthor-time 1777992000\nauthor-tz +0200\ncommitter Hina Tanaka\ncommitter-mail <hina.tanaka@example.com>\ncommitter-time 1777992000\ncommitter-tz +0200\nsummary docs: add README and pyproject.toml with calc console-script entry\nfilename README.md\n\t# Arithmetic Expression Evaluator\nb640390c8aae2617b88a22e343de605d2e7e0b9c 2 2\n\t\nb640390c8aae2617b88a22e343de605d2e7e0b9c 3 3\n\tA command-line calculator that reads one arithmetic expression per line from\nb640390c8aae2617b88a22e343de605d2e7e0b9c 4 4\n\tstandard input and prints the result.\nb640390c8aae2617b88a22e343de605d2e7e0b9c 5 5\n\t\nb640390c8aae2617b88a22e343de605d2e7e0b9c 6 6\n\t## Running\nb640390c8aae2617b88a22e343de605d2e7e0b9c 7 7\n\t\nb640390c8aae2617b88a22e343de605d2e7e0b9c 8 8\n\t```\nb640390c8aae2617b88a22e343de605d2e7e0b9c 9 9\n\tpython evaluator.py\nb640390c8aae2617b88a22e343de605d2e7e0b9c 10 10\n\t```\nb640390c8aae2617b88a22e343de605d2e7e0b9c 11 11\n\t\nb640390c8aae2617b88a22e343de605d2e7e0b9c 12 12\n\tOr, after installing the package:\nb640390c8aae2617b88a22e343de605d2e7e0b9c 13 13\n\t\nb640390c8aae2617b88a22e343de605d2e7e0b9c 14 14\n\t```\nb640390c8aae2617b88a22e343de605d2e7e0b9c 15 15\n\tpip install -e .\nb640390c8aae2617b88a22e343de605d2e7e0b9c 16 16\n\tcalc\nb640390c8aae2617b88a22e343de605d2e7e0b9c 17 17\n\t```\nb640390c8aae2617b88a22e343de605d2e7e0b9c 18 18\n\t\nb640390c8aae2617b88a22e343de605d2e7e0b9c 19 19\n\t## Example sessions\nb640390c8aae2617b88a22e343de605d2e7e0b9c 20 20\n\t\nb640390c8aae2617b88a22e343de605d2e7e0b9c 21 21\n\t```\nb640390c8aae2617b88a22e343de605d2e7e0b9c 22 22\n\t$ python evaluator.py\nb640390c8aae2617b88a22e343de605d2e7e0b9c 23 23\n\t1 + 2 * 3\nb640390c8aae2617b88a22e343de605d2e7e0b9c 24 24\n\t7\nb640390c8aae2617b88a22e343de605d2e7e0b9c 25 25\n\t(1 + 2) * 3\nb640390c8aae2617b88a22e343de605d2e7e0b9c 26 26\n\t9\nb640390c8aae2617b88a22e343de605d2e7e0b9c 27 27\n\t10 / 4\nb640390c8aae2617b88a22e343de605d2e7e0b9c 28 28\n\t2.5\nb640390c8aae2617b88a22e343de605d2e7e0b9c 29 29\n\t-3 + 1\nb640390c8aae2617b88a22e343de605d2e7e0b9c 30 30\n\t-2\nb640390c8aae2617b88a22e343de605d2e7e0b9c 31 31\n\t```\nb640390c8aae2617b88a22e343de605d2e7e0b9c 32 32\n\t\nb640390c8aae2617b88a22e343de605d2e7e0b9c 33 33\n\t```\nb640390c8aae2617b88a22e343de605d2e7e0b9c 34 34\n\t$ echo "2.5 * (1 + 3)" | python evaluator.py\nb640390c8aae2617b88a22e343de605d2e7e0b9c 35 35\n\t10.0\nb640390c8aae2617b88a22e343de605d2e7e0b9c 36 36\n\t```\nb640390c8aae2617b88a22e343de605d2e7e0b9c 37 37\n\t\nb640390c8aae2617b88a22e343de605d2e7e0b9c 38 38\n\t## Supported operators\nb640390c8aae2617b88a22e343de605d2e7e0b9c 39 39\n\t\nb640390c8aae2617b88a22e343de605d2e7e0b9c 40 40\n\t| Operator | Meaning        |\nb640390c8aae2617b88a22e343de605d2e7e0b9c 41 41\n\t|----------|----------------|\nb640390c8aae2617b88a22e343de605d2e7e0b9c 42 42\n\t| `+`      | Addition       |\nb640390c8aae2617b88a22e343de605d2e7e0b9c 43 43\n\t| `-`      | Subtraction    |\nb640390c8aae2617b88a22e343de605d2e7e0b9c 44 44\n\t| `*`      | Multiplication |\nb640390c8aae2617b88a22e343de605d2e7e0b9c 45 45\n\t| `/`      | Division       |\nb640390c8aae2617b88a22e343de605d2e7e0b9c 46 46\n\t\nb640390c8aae2617b88a22e343de605d2e7e0b9c 47 47\n\tOperator precedence follows standard arithmetic rules (`*` and `/` before `+`\nb640390c8aae2617b88a22e343de605d2e7e0b9c 48 48\n\tand `-`). Parentheses can override precedence. Unary `+` and `-` are supported.\nb640390c8aae2617b88a22e343de605d2e7e0b9c 49 49\n\t\nb640390c8aae2617b88a22e343de605d2e7e0b9c 50 50\n\t## Error behaviour\nb640390c8aae2617b88a22e343de605d2e7e0b9c 51 51\n\t\nb640390c8aae2617b88a22e343de605d2e7e0b9c 52 52\n\tInvalid input prints `Error: <reason>` on the same line and processing\nb640390c8aae2617b88a22e343de605d2e7e0b9c 53 53\n\tcontinues with the next line. The calculator never crashes on bad input.\nb640390c8aae2617b88a22e343de605d2e7e0b9c 54 54\n\t\nb640390c8aae2617b88a22e343de605d2e7e0b9c 55 55\n\t```\nb640390c8aae2617b88a22e343de605d2e7e0b9c 56 56\n\t$ echo "1 /" | python evaluator.py\nb640390c8aae2617b88a22e343de605d2e7e0b9c 57 57\n\tError: unexpected end of input\nb640390c8aae2617b88a22e343de605d2e7e0b9c 58 58\n\t$ echo "1 / 0" | python evaluator.py\nb640390c8aae2617b88a22e343de605d2e7e0b9c 59 59\n\tError: division by zero\nb640390c8aae2617b88a22e343de605d2e7e0b9c 60 60\n\t```\n',
