          "tokenizer.py":
            '32a0759311cad68b599436351b46720ca30786eb 1 1 46\nauthor Marisol Adeyemi\nauthor-mail <marisol.adeyemi@example.com>\nauthor-time 1776846600\nauthor-tz +0200\ncommitter Marisol Adeyemi\ncommitter-mail <marisol.adeyemi@example.com>\ncommitter-time 1776846600\ncommitter-tz +0200\nsummary feat: add tokenizer for numbers, operators, and parentheses\nboundary\nfilename tokenizer.py\n\timport re\n32a0759311cad68b599436351b46720ca30786eb 2 2\n\tfrom dataclasses import dataclass\n32a0759311cad68b599436351b46720ca30786eb 3 3\n\tfrom enum import Enum, auto\n32a0759311cad68b599436351b46720ca30786eb 4 4\n\t\n32a0759311cad68b599436351b46720ca30786eb 5 5\n\t\n32a0759311cad68b599436351b46720ca30786eb 6 6\n\tclass TokenType(Enum):\n32a0759311cad68b599436351b46720ca30786eb 7 7\n\t    NUMBER = auto()\n32a0759311cad68b599436351b46720ca30786eb 8 8\n\t    PLUS = auto()\n32a0759311cad68b599436351b46720ca30786eb 9 9\n\t    MINUS = auto()\n32a0759311cad68b599436351b46720ca30786eb 10 10\n\t    STAR = auto()\n32a0759311cad68b599436351b46720ca30786eb 11 11\n\t    SLASH = auto()\n32a0759311cad68b599436351b46720ca30786eb 12 12\n\t    LPAREN = auto()\n32a0759311cad68b599436351b46720ca30786eb 13 13\n\t    RPAREN = auto()\n32a0759311cad68b599436351b46720ca30786eb 14 14\n\t\n32a0759311cad68b599436351b46720ca30786eb 15 15\n\t\n32a0759311cad68b599436351b46720ca30786eb 16 16\n\t@dataclass\n32a0759311cad68b599436351b46720ca30786eb 17 17\n\tclass Token:\n32a0759311cad68b599436351b46720ca30786eb 18 18\n\t    type: TokenType\n32a0759311cad68b599436351b46720ca30786eb 19 19\n\t    value: str\n32a0759311cad68b599436351b46720ca30786eb 20 20\n\t\n32a0759311cad68b599436351b46720ca30786eb 21 21\n\t\n32a0759311cad68b599436351b46720ca30786eb 22 22\n\t_TOKEN_RE = re.compile(\n32a0759311cad68b599436351b46720ca30786eb 23 23\n\t    r"\\d+\\.\\d+|\\d+|[+\\-*/()]|\\S"\n32a0759311cad68b599436351b46720ca30786eb 24 24\n\t)\n32a0759311cad68b599436351b46720ca30786eb 25 25\n\t\n32a0759311cad68b599436351b46720ca30786eb 26 26\n\t_CHAR_TO_TYPE = {\n32a0759311cad68b599436351b46720ca30786eb 27 27\n\t    "+": TokenType.PLUS,\n32a0759311cad68b599436351b46720ca30786eb 28 28\n\t    "-": TokenType.MINUS,\n32a0759311cad68b599436351b46720ca30786eb 29 29\n\t    "*": TokenType.STAR,\n32a0759311cad68b599436351b46720ca30786eb 30 30\n\t    "/": TokenType.SLASH,\n32a0759311cad68b599436351b46720ca30786eb 31 31\n\t    "(": TokenType.LPAREN,\n32a0759311cad68b599436351b46720ca30786eb 32 32\n\t    ")": TokenType.RPAREN,\n32a0759311cad68b599436351b46720ca30786eb 33 33\n\t}\n32a0759311cad68b599436351b46720ca30786eb 34 34\n\t\n32a0759311cad68b599436351b46720ca30786eb 35 35\n\t\n32a0759311cad68b599436351b46720ca30786eb 36 36\n\tdef tokenize(line: str) -> list[Token]:\n32a0759311cad68b599436351b46720ca30786eb 37 37\n\t    tokens: list[Token] = []\n32a0759311cad68b599436351b46720ca30786eb 38 38\n\t    for m in _TOKEN_RE.finditer(line):\n32a0759311cad68b599436351b46720ca30786eb 39 39\n\t        s = m.group()\n32a0759311cad68b599436351b46720ca30786eb 40 40\n\t        if s[0].isdigit():\n32a0759311cad68b599436351b46720ca30786eb 41 41\n\t            tokens.append(Token(TokenType.NUMBER, s))\n32a0759311cad68b599436351b46720ca30786eb 42 42\n\t        elif s in _CHAR_TO_TYPE:\n32a0759311cad68b599436351b46720ca30786eb 43 43\n\t            tokens.append(Token(_CHAR_TO_TYPE[s], s))\n32a0759311cad68b599436351b46720ca30786eb 44 44\n\t        else:\n32a0759311cad68b599436351b46720ca30786eb 45 45\n\t            raise ValueError(f"Unknown character: {s!r}")\n32a0759311cad68b599436351b46720ca30786eb 46 46\n\t    return tokens\n',
